package metric

import (
	"context"
	"encoding/json"
	"os"
	"path/filepath"
	"sync"
	"testing"
	"time"

	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func writeMetricArtifact(t *testing.T, wd, id string) {
	t.Helper()
	path := filepath.Join(wd, "docs", "metrics", id+".md")
	require.NoError(t, os.MkdirAll(filepath.Dir(path), 0o755))
	content := "---\nddx:\n  id: " + id + "\n---\n# " + id + "\n"
	require.NoError(t, os.WriteFile(path, []byte(content), 0o644))
}

func writeArtifact(t *testing.T, wd, dir, id string) {
	t.Helper()
	path := filepath.Join(wd, "docs", dir, id+".md")
	require.NoError(t, os.MkdirAll(filepath.Dir(path), 0o755))
	content := "---\nddx:\n  id: " + id + "\n---\n# " + id + "\n"
	require.NoError(t, os.WriteFile(path, []byte(content), 0o644))
}

func writeMetricDefinition(t *testing.T, wd string, def Definition) {
	t.Helper()
	store := ddxexec.NewStore(wd)
	require.NoError(t, store.SaveDefinition(ddxexec.Definition{
		ID:          def.DefinitionID,
		ArtifactIDs: []string{def.MetricID},
		Executor: ddxexec.ExecutorSpec{
			Kind:    ddxexec.ExecutorKindCommand,
			Command: append([]string{}, def.Command...),
			Cwd:     def.Cwd,
			Env:     cloneStringMap(def.Env),
		},
		Result: ddxexec.ResultSpec{
			Metric: &ddxexec.MetricResultSpec{
				Unit: def.Thresholds.Unit,
			},
		},
		Evaluation: ddxexec.Evaluation{
			Comparison: def.Comparison,
			Thresholds: ddxexec.Thresholds{
				WarnMS:    def.Thresholds.Warn,
				RatchetMS: def.Thresholds.Ratchet,
			},
		},
		Active:    def.Active,
		CreatedAt: def.CreatedAt,
	}))
}

func TestValidateRunAndHistory(t *testing.T) {
	wd := t.TempDir()
	writeMetricArtifact(t, wd, "MET-001")
	writeMetricDefinition(t, wd, Definition{
		DefinitionID: "metric-startup-time@1",
		MetricID:     "MET-001",
		Command:      []string{"sh", "-c", "printf '14.6ms\\n'"},
		Thresholds:   Thresholds{Warn: 20, Ratchet: 30, Unit: "ms"},
		Comparison:   ComparisonLowerIsBetter,
		Active:       true,
		CreatedAt:    mustTime(t, "2026-04-04T15:00:00Z"),
	})

	store := NewStore(wd)
	def, doc, err := store.Validate("MET-001")
	require.NoError(t, err)
	require.Equal(t, "metric-startup-time@1", def.DefinitionID)
	require.Equal(t, "MET-001", doc.ID)

	rec, err := store.Run(context.Background(), "MET-001")
	require.NoError(t, err)
	assert.Equal(t, StatusPass, rec.Status)
	assert.InDelta(t, 14.6, rec.Value, 0.01)
	assert.Equal(t, "ms", rec.Unit)
	assert.Equal(t, "MET-001", rec.ArtifactID)

	history, err := store.History("MET-001")
	require.NoError(t, err)
	require.Len(t, history, 1)
	assert.Equal(t, rec.RunID, history[0].RunID)
}

func TestDefinitionAndHistoryPreferMetricArtifactID(t *testing.T) {
	wd := t.TempDir()
	writeMetricArtifact(t, wd, "MET-001")
	writeArtifact(t, wd, "misc", "DOC-001")
	writeMetricDefinition(t, wd, Definition{
		DefinitionID: "metric-startup-time@1",
		MetricID:     "MET-001",
		Command:      []string{"sh", "-c", "printf '14.6ms\\n'"},
		Thresholds:   Thresholds{Warn: 20, Ratchet: 30, Unit: "ms"},
		Comparison:   ComparisonLowerIsBetter,
		Active:       true,
		CreatedAt:    mustTime(t, "2026-04-04T15:00:00Z"),
	})

	store := NewStore(wd)
	def, err := store.LoadDefinition("MET-001")
	require.NoError(t, err)
	assert.Equal(t, "MET-001", def.MetricID)

	rec, err := store.Run(context.Background(), "MET-001")
	require.NoError(t, err)
	assert.Equal(t, "MET-001", rec.ArtifactID)
	assert.Equal(t, "MET-001", rec.MetricID)

	history, err := store.History("MET-001")
	require.NoError(t, err)
	require.Len(t, history, 1)
	assert.Equal(t, "MET-001", history[0].MetricID)
	assert.Equal(t, "MET-001", history[0].ArtifactID)
}

func TestCompareAndTrend(t *testing.T) {
	wd := t.TempDir()
	writeMetricArtifact(t, wd, "MET-001")
	writeMetricDefinition(t, wd, Definition{
		DefinitionID: "metric-startup-time@1",
		MetricID:     "MET-001",
		Command:      []string{"sh", "-c", "printf '20ms\\n'"},
		Thresholds:   Thresholds{Warn: 20, Ratchet: 30, Unit: "ms"},
		Comparison:   ComparisonLowerIsBetter,
		Active:       true,
		CreatedAt:    mustTime(t, "2026-04-04T15:00:00Z"),
	})

	store := NewStore(wd)
	firstRec, err := store.Run(context.Background(), "MET-001")
	require.NoError(t, err)
	writeMetricDefinition(t, wd, Definition{
		DefinitionID: "metric-startup-time@1",
		MetricID:     "MET-001",
		Command:      []string{"sh", "-c", "printf '14.6ms\\n'"},
		Thresholds:   Thresholds{Warn: 20, Ratchet: 30, Unit: "ms"},
		Comparison:   ComparisonLowerIsBetter,
		Active:       true,
		CreatedAt:    mustTime(t, "2026-04-04T15:01:00Z"),
	})
	secondRec, err := store.Run(context.Background(), "MET-001")
	require.NoError(t, err)

	latest, result, err := store.Compare("MET-001", "baseline")
	require.NoError(t, err)
	assert.Equal(t, secondRec.RunID, latest.RunID)
	assert.Equal(t, 20.0, result.Baseline)
	assert.InDelta(t, -5.4, result.Delta, 0.01)

	trend, err := store.Trend("MET-001")
	require.NoError(t, err)
	assert.Equal(t, 2, trend.Count)
	assert.InDelta(t, 14.6, trend.Latest, 0.01)
	assert.InDelta(t, 17.3, trend.Average, 0.01)
	assert.NotEmpty(t, firstRec.RunID)
}

func TestConcurrentHistoryWrites(t *testing.T) {
	wd := t.TempDir()
	writeMetricArtifact(t, wd, "MET-001")
	writeMetricDefinition(t, wd, Definition{
		DefinitionID: "metric-startup-time@1",
		MetricID:     "MET-001",
		Command:      []string{"sh", "-c", "printf '14.6ms\\n'"},
		Thresholds:   Thresholds{Warn: 20, Ratchet: 30, Unit: "ms"},
		Comparison:   ComparisonLowerIsBetter,
		Active:       true,
		CreatedAt:    mustTime(t, "2026-04-04T15:00:00Z"),
	})

	store := NewStore(wd)
	const writers = 12
	var wg sync.WaitGroup
	errCh := make(chan error, writers)
	for i := 0; i < writers; i++ {
		wg.Add(1)
		go func(i int) {
			defer wg.Done()
			_, err := store.Run(context.Background(), "MET-001")
			errCh <- err
		}(i)
	}
	wg.Wait()
	close(errCh)
	for err := range errCh {
		require.NoError(t, err)
	}

	raw, err := os.ReadFile(filepath.Join(wd, ".ddx", "exec-runs.jsonl"))
	require.NoError(t, err)
	lines := 0
	for _, b := range raw {
		if b == '\n' {
			lines++
		}
	}
	assert.Equal(t, writers, lines)

	history, err := store.History("MET-001")
	require.NoError(t, err)
	assert.Len(t, history, writers)
}

func mustTime(t *testing.T, value string) time.Time {
	t.Helper()
	parsed, err := time.Parse(time.RFC3339, value)
	require.NoError(t, err)
	return parsed
}

// TestLegacyMetricsDirIgnored verifies that a pre-exec .ddx/metrics/ directory
// left over from a pre-release build does not cause DDx to crash. The current
// metric store delegates to the exec substrate and never reads .ddx/metrics/.
func TestLegacyMetricsDirIgnored(t *testing.T) {
	wd := t.TempDir()

	// Simulate old-format .ddx/metrics/ data written by the pre-exec metric store.
	metricsDir := filepath.Join(wd, ".ddx", "metrics")
	defsDir := filepath.Join(metricsDir, "definitions")
	require.NoError(t, os.MkdirAll(defsDir, 0o755))

	oldDef := `{"definition_id":"metric-startup-time@1","metric_id":"MET-001","command":["sh","-c","echo 10ms"],"active":true,"created_at":"2026-04-04T10:00:00Z"}`
	require.NoError(t, os.WriteFile(filepath.Join(defsDir, "metric-startup-time@1.json"), []byte(oldDef), 0o644))

	oldHistory := `{"run_id":"MET-001@1","metric_id":"MET-001","definition_id":"metric-startup-time@1","observed_at":"2026-04-04T10:00:01Z","status":"pass","value":10,"unit":"ms"}` + "\n"
	require.NoError(t, os.WriteFile(filepath.Join(metricsDir, "history.jsonl"), []byte(oldHistory), 0o644))

	// The current store must not crash when .ddx/metrics/ exists.
	store := NewStore(wd)

	// History returns empty — legacy metrics/ data is not read.
	history, err := store.History("MET-001")
	require.NoError(t, err)
	assert.Empty(t, history)
}

func TestSaveDefinitionRoundTrips(t *testing.T) {
	wd := t.TempDir()
	store := ddxexec.NewStore(wd)
	def := Definition{
		DefinitionID: "metric-startup-time@1",
		MetricID:     "MET-001",
		Command:      []string{"sh", "-c", "printf '14.6ms\\n'"},
		Thresholds:   Thresholds{Warn: 20, Ratchet: 30, Unit: "ms"},
		Comparison:   ComparisonLowerIsBetter,
		Active:       true,
		CreatedAt:    mustTime(t, "2026-04-04T15:00:00Z"),
	}
	require.NoError(t, store.SaveDefinition(ddxexec.Definition{
		ID:          def.DefinitionID,
		ArtifactIDs: []string{def.MetricID},
		Executor: ddxexec.ExecutorSpec{
			Kind:    ddxexec.ExecutorKindCommand,
			Command: append([]string{}, def.Command...),
			Cwd:     def.Cwd,
			Env:     cloneStringMap(def.Env),
		},
		Result: ddxexec.ResultSpec{
			Metric: &ddxexec.MetricResultSpec{
				Unit: def.Thresholds.Unit,
			},
		},
		Evaluation: ddxexec.Evaluation{
			Comparison: def.Comparison,
			Thresholds: ddxexec.Thresholds{
				WarnMS:    def.Thresholds.Warn,
				RatchetMS: def.Thresholds.Ratchet,
			},
		},
		Active:    def.Active,
		CreatedAt: def.CreatedAt,
	}))

	loaded, err := NewStore(wd).LoadDefinition("MET-001")
	require.NoError(t, err)
	raw, err := json.Marshal(loaded)
	require.NoError(t, err)
	assert.Contains(t, string(raw), "metric-startup-time@1")
}

package cmd

import (
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/metric"
	"github.com/spf13/cobra"
)

func (f *CommandFactory) newMetricCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "metric",
		Short: "Inspect and run metric artifacts",
		Long:  "Manage DDx metric artifacts, run definitions, and observation history through ddx exec.",
		Run: func(cmd *cobra.Command, args []string) {
			_ = cmd.Help()
		},
	}

	cmd.AddCommand(f.newMetricValidateCommand())
	cmd.AddCommand(f.newMetricListCommand())
	cmd.AddCommand(f.newMetricShowCommand())
	cmd.AddCommand(f.newMetricRunCommand())
	cmd.AddCommand(f.newMetricCompareCommand())
	cmd.AddCommand(f.newMetricHistoryCommand())
	cmd.AddCommand(f.newMetricTrendCommand())

	return cmd
}

func (f *CommandFactory) metricStore() *metric.Store {
	return metric.NewStore(f.WorkingDir)
}

func (f *CommandFactory) metricHistory(metricID string) ([]metric.HistoryRecord, error) {
	return f.metricStore().History(metricID)
}

func (f *CommandFactory) newMetricValidateCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "validate <metric-id>",
		Short: "Validate a metric artifact and runtime definition",
		Args:  cobra.ExactArgs(1),
		RunE:  f.runMetricValidateCommand,
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricListCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "list",
		Short: "List metric artifacts",
		RunE:  f.runMetricListCommand,
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricShowCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "show <metric-id>",
		Short: "Show one metric artifact and recent history",
		Args:  cobra.ExactArgs(1),
		RunE:  f.runMetricShowCommand,
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricRunCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "run <metric-id>",
		Short: "Execute a metric definition",
		Args:  cobra.ExactArgs(1),
		RunE:  f.runMetricRunCommand,
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricCompareCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "compare <metric-id>",
		Short: "Compare the latest metric run to a target",
		Args:  cobra.ExactArgs(1),
		RunE:  f.runMetricCompareCommand,
	}
	cmd.Flags().String("against", "latest", "Compare against baseline, latest, or a run ID")
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricHistoryCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "history <metric-id>",
		Short: "Show metric observation history",
		Args:  cobra.ExactArgs(1),
		RunE:  f.runMetricHistoryCommand,
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) newMetricTrendCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "trend <metric-id>",
		Short: "Summarize metric observations over time",
		Args:  cobra.ExactArgs(1),
		RunE:  f.runMetricTrendCommand,
	}
	cmd.Flags().Bool("json", false, "Output JSON")
	return cmd
}

func (f *CommandFactory) runMetricValidateCommand(cmd *cobra.Command, args []string) error {
	def, _, err := f.metricStore().Validate(args[0])
	if err != nil {
		return err
	}
	if cmd.Flags().Changed("json") {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(map[string]any{
			"metric_id":     args[0],
			"definition_id": def.DefinitionID,
			"status":        "ok",
		})
	}
	fmt.Fprintf(cmd.OutOrStdout(), "%s validated with %s\n", args[0], def.DefinitionID)
	return nil
}

func (f *CommandFactory) runMetricListCommand(cmd *cobra.Command, args []string) error {
	docs, err := f.metricStore().ListArtifacts()
	if err != nil {
		return err
	}
	if cmd.Flags().Changed("json") {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(docs)
	}
	for _, doc := range docs {
		if doc.Title != "" {
			fmt.Fprintf(cmd.OutOrStdout(), "%s  %s\n", doc.ID, doc.Title)
			continue
		}
		fmt.Fprintln(cmd.OutOrStdout(), doc.ID)
	}
	return nil
}

func (f *CommandFactory) runMetricShowCommand(cmd *cobra.Command, args []string) error {
	def, doc, err := f.metricStore().Validate(args[0])
	if err != nil {
		return err
	}
	history, err := f.metricHistory(args[0])
	if err != nil {
		return err
	}
	recent := history
	if len(recent) > 5 {
		recent = recent[len(recent)-5:]
	}
	if cmd.Flags().Changed("json") {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(map[string]any{
			"artifact":       doc,
			"definition":     def,
			"recent_history": recent,
		})
	}
	fmt.Fprintf(cmd.OutOrStdout(), "ID:        %s\n", doc.ID)
	if doc.Title != "" {
		fmt.Fprintf(cmd.OutOrStdout(), "Title:     %s\n", doc.Title)
	}
	fmt.Fprintf(cmd.OutOrStdout(), "Path:      %s\n", doc.Path)
	fmt.Fprintf(cmd.OutOrStdout(), "Definition: %s\n", def.DefinitionID)
	fmt.Fprintf(cmd.OutOrStdout(), "Command:   %s\n", joinCommand(def.Command))
	fmt.Fprintf(cmd.OutOrStdout(), "Created:   %s\n", def.CreatedAt.Format(time.RFC3339))
	fmt.Fprintln(cmd.OutOrStdout(), "Recent history:")
	if len(recent) == 0 {
		fmt.Fprintln(cmd.OutOrStdout(), "  (none)")
		return nil
	}
	for _, rec := range recent {
		fmt.Fprintf(cmd.OutOrStdout(), "  %s  %s  %.3f%s  %s\n", rec.ObservedAt.Format(time.RFC3339), rec.RunID, rec.Value, rec.Unit, rec.Status)
	}
	return nil
}

func (f *CommandFactory) runMetricRunCommand(cmd *cobra.Command, args []string) error {
	rec, err := f.metricStore().Run(cmd.Context(), args[0])
	if err != nil {
		return err
	}
	if cmd.Flags().Changed("json") {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(rec)
	}
	fmt.Fprintf(cmd.OutOrStdout(), "%s  %s  %.3f%s  %s\n", rec.ObservedAt.Format(time.RFC3339), rec.Status, rec.Value, rec.Unit, rec.RunID)
	return nil
}

func (f *CommandFactory) runMetricCompareCommand(cmd *cobra.Command, args []string) error {
